SELECT TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') AS connDt FROM DUAL
/* ====== cmn.login.insertLog =========*/
INSERT INTO CMN_MENU_CONN_LOG_MST ( MENU_ID , USR_ID , CONN_DT , IP_INFO , MENU_NM , DUTY_NM ) SELECT #{MENU_ID} , SUBSTRB(#{SESSION_USER_ID},1,10) /* ID0005*/ --, TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') , #{connDt} , #{IP_INFO} , A.MENU_NM , A.DUTY_NM FROM CMN_MENU_MST A WHERE MENU_ID = #{MENU_ID} /* 'MSP2000001' */ AND NOT EXISTS ( SELECT 1 FROM CMN_MENU_CONN_LOG_MST WHERE MENU_ID = #{MENU_ID} AND USR_ID = SUBSTRB(#{SESSION_USER_ID},1,10) AND CONN_DT = #{connDt} )
